import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import './App.css';

// --- 1. КОМПОНЕНТ МЕНЮ ---
const Menu = ({ user, onOrder }) => {
  const items = [
    { id: 1, name: 'Эспрессо', price: 150, img: '☕' },
    { id: 2, name: 'Капучино', price: 250, img: '🥛' },
    { id: 3, name: 'Круассан', price: 210, img: '🥐' }
  ];

  return (
    <div className="page">
      <h2>Меню кофейни</h2>
      <div className="product-grid">
        {items.map(item => (
          <div key={item.id} className="product-card" onClick={() => onOrder(item)}>
            <span style={{fontSize: '40px'}}>{item.img}</span>
            <h3>{item.name}</h3>
            <p>{item.price} ₽</p>
          </div>
        ))}
      </div>
    </div>
  );
};

// --- 2. КОМПОНЕНТ ПРОФИЛЯ ---
const Profile = ({ orders, onLogout }) => (
  <div className="page">
    <h2>Личный кабинет</h2>
    <div className="user-info-card">
      <div className="avatar">👤</div>
      <p>Вы вошли как: <strong>Любимый гость</strong></p>
      <button onClick={onLogout} className="btn-logout">Выйти из аккаунта</button>
    </div>

    <h3>История заказов</h3>
    <div className="order-history">
      {orders.length === 0 ? <p>Заказов пока нет</p> : 
        orders.map(o => (
          <div key={o.id} className={`order-item ${o.status === 'Готов' ? 'ready' : ''}`}>
            <span>#{o.id} — {o.description}</span>
            <span className="status-label">{o.status}</span>
          </div>
        ))
      }
    </div>
  </div>
);

// --- 3. ЭКРАН ЛОГИНА ---
const AuthScreen = ({ onLogin, onRegister }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [pass, setPass] = useState('');
  const [name, setName] = useState('');

  const handleSubmit = () => {
    if (isLogin) {
      onLogin(email, pass);
    } else {
      if (!name) return alert("Введите ваше имя");
      onRegister(name, email, pass);
    }
  };

  return (
    <div className="login-page">
      <div className="login-card fade-in">
        <h2>{isLogin ? 'С возвращением!' : 'Стать гостем'}</h2>
        <p className="subtitle">Кофейня Etika</p>

        {!isLogin && (
          <input type="text" placeholder="Ваше имя" value={name} onChange={e => setName(e.target.value)} />
        )}
        <input type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} />
        <input type="password" placeholder="Пароль" value={pass} onChange={e => setPass(e.target.value)} />

        <button className="btn-main" onClick={handleSubmit}>
          {isLogin ? 'Войти в рай' : 'Зарегистрироваться'}
        </button>

        <p className="toggle-auth" onClick={() => setIsLogin(!isLogin)}>
          {isLogin ? 'Нет аккаунта? Создать' : 'Уже есть аккаунт? Войти'}
        </p>
      </div>
    </div>
  );
};

// --- 4. ОСНОВНОЙ КОМПОНЕНТ APP ---
export default function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));
  const [orders, setOrders] = useState([]);

  const login = async (email, password) => {
    const res = await fetch('http://localhost:8000/index.php', {
      method: 'POST',
      body: JSON.stringify({ action: 'login', email, password })
    });
    const data = await res.json();
    if (data.id) {
      setUser(data);
      localStorage.setItem('user', JSON.stringify(data));
    } else {
      alert(data.error || "Ошибка входа");
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('user');
  };

  const handleOrder = async (item) => {
    await fetch('http://localhost:8000/index.php', {
      method: 'POST',
      body: JSON.stringify({ user_id: user.id, description: item.name, total_amount: item.price })
    });
    alert('Заказ принят!');
  };

  useEffect(() => {
    if (user) {
      const fetchOrders = () => {
        fetch(`http://localhost:8000/index.php?user_id=${user.id}`)
          .then(res => res.json())
          .then(data => setOrders(Array.isArray(data) ? data : []));
      };
      fetchOrders();
      const interval = setInterval(fetchOrders, 3000);
      return () => clearInterval(interval);
    }
  }, [user]);

  if (!user) return <LoginScreen onLogin={login} />;

  return (
    <Router>
      <div className="paradise-app">
        <Routes>
          <Route path="/" element={<Menu user={user} onOrder={handleOrder} />} />
          <Route path="/profile" element={<Profile orders={orders} onLogout={logout} />} />
        </Routes>

        <nav className="bottom-nav">
          <Link to="/" className="nav-item">🍴 Меню</Link>
          <Link to="/profile" className="nav-item">👤 Профиль</Link>
        </nav>
      </div>
    </Router>
  );
}
